import { Justtrylinks } from "@components/common/justtrylinks";
import TalkToUsNew from "@components/common/talk-to-us-new";
import { Link } from "@reach/router";
import { StaticImage } from "gatsby-plugin-image";
import React from "react";

const hero = (props) => {
  const { db } = props;
  return (
    <section className="hero-wrapper flex-center md-flex-column gap-2xl">
      <div className="item-start gap-lg hero-content-section ">
        <h1 className="about-h2-v2 font-black font-black">
          Cryptocurrency Exchange Development Company
        </h1>
        <p className="about-p">
          Build a secure and feature-rich cryptocurrency exchange platform with
          Justtry Technologies. We deliver end-to-end crypto exchange
          development solutions with advanced security, high performance, and
          seamless trading experiences.
        </p>
        <div className="buttons">
          <Link to={Justtrylinks.contactUs} className="roll-button roll-btn">
            <span>View Live Demo</span>
          </Link>
          <TalkToUsNew
            db={db}
            label="Free Consultation"
            customClass="normal-roll-button normal-roll-btn"
          />
        </div>
      </div>
      <div>
        <StaticImage
          src="../../../styles/assets/images/Crypto/crypto_home.png"
          alt="crypto exchange"
          fetchpriority="high"
          layout="constrained"
          width={1800}
          loading="eager"
          placeholder="none"
        />
      </div>
    </section>
  );
};

export default hero;
