import React from "react";
import xrp from "@styles/assets/images/Crypto/xrp.svg";
import ethereum from "@styles/assets/images/Crypto/ethereum.svg";
import bitcoin from "@styles/assets/images/Crypto/bitcoin.svg";
import solana from "@styles/assets/images/Crypto/solana.svg";
import polygon from "@styles/assets/images/Crypto/polygon.svg";
import hyperledger from "@styles/assets/images/Crypto/hyperledger.svg";
import bnb from "@styles/assets/images/Crypto/bnb.svg";
import bch from "@styles/assets/images/Crypto/bch.svg";
import basechain from "@styles/assets/images/Crypto/basechain.svg";
import avalanche from "@styles/assets/images/Crypto/avalanche.svg";

const boxData = [
  {
    title: "Bitcoin",
    icon: bitcoin,
  },
  {
    title: "Ethereum",
    icon: ethereum,
  },
  {
    title: "Polygon",
    icon: polygon,
  },
  {
    title: "Solana",
    icon: solana,
  },
  {
    title: "BNB",
    icon: bnb,
  },
  {
    title: "XRP",
    icon: xrp,
  },
  {
    title: "Avalanche",
    icon: avalanche,
  },
  {
    title: "Base Chain",
    icon: basechain,
  },
  {
    title: "BCH",
    icon: bch,
  },
  {
    title: "Hyperledger",
    icon: hyperledger,
  },
];

const blockChainNetwork = () => {
  return (
    <section className="hero-wrapper item-center gap-2xl">
      <h2 className="about-h2 font-black c-text-center md-c-text-start">
        Blockchain Networks for Cryptocurrency Exchange Development
      </h2>
      <p className="about-p c-text-center md-c-text-start">
        We deliver crypto exchange development services across top blockchain
        networks, including Bitcoin, Ethereum, Polygon, Solana, BNB, and more.
        Our multi-chain expertise ensures high-performance trading platforms.
      </p>
      <div className="c-grid grid-five crypto-network-cards">
        {boxData.map((data, index) => (
          <div key={index} className="crypto-network-card item-center">
            <img src={data.icon} alt={data.title} />
            <p className="about-p fw-600">{data.title}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default blockChainNetwork;
