import { Justtrylinks } from "@components/common/justtrylinks";
import TalkToUsNew from "@components/common/talk-to-us-new";
import { Link } from "@reach/router";
import React from "react";

import poloniex from "@styles/assets/images/Crypto/poloniex.svg";
import wazirx from "@styles/assets/images/Crypto/wazirx.svg";
import binance from "@styles/assets/images/Crypto/binance.svg";
import coinbx from "@styles/assets/images/Crypto/coinbx.svg";
import huobi from "@styles/assets/images/Crypto/huobi.svg";
import kucoin from "@styles/assets/images/Crypto/kucoin.svg";

const boxData = [
  { title: "Wazirx", icon: wazirx, link: Justtrylinks.wazirxCloneScript },
  { title: "Binance", icon: binance, link: Justtrylinks.binanceCloneScript },
  { title: "Coinbase", icon: coinbx },
  { title: "kucoin", icon: kucoin },
  { title: "Huobi", icon: huobi },
  { title: "Poloniex", icon: poloniex },
];

const cloneScripts = (props) => {
  const { db } = props;
  return (
    <section className="light-gray-bg">
      <div className="hero-wrapper item-center gap-2xl">
        <div className="item-center gap-lg">
          <h2 className="about-h2 font-black c-text-center md-c-text-start">
            Instantly Launch Your Crypto Exchange with Our Clone Script
          </h2>
          <p className="about-p c-text-center md-c-text-start">
            Accelerate your crypto business launch with our ready-to-deploy
            <Link to={Justtrylinks.binanceCloneScript}>
              {" "}
              cryptocurrency exchange clone script
            </Link>
            . Our secure and fully customizable solution enables you to launch a
            feature-rich exchange platform quickly, reduce development time, and
            enter the crypto market with confidence.
          </p>
        </div>
        <div className="clone-scripts-coins c-grid grid-three gap-xl">
          {boxData.map((data, index) => (
            <div className="clone-scripts-coin flex-center gap-xl" key={index}>
              <img src={data.icon} alt={data.title} />

              {data.link ? (
                <Link to={data.link} className="about-p-two font-black fw-600">
                  {data.title}
                </Link>
              ) : (
                <span className="about-p-two fw-600">{data.title}</span>
              )}
            </div>
          ))}
        </div>

        <div className="buttons">
          <Link to={Justtrylinks.contactUs} className="roll-button roll-btn">
            <span>View Live Demo</span>
          </Link>
          <TalkToUsNew
            db={db}
            label="Free Consultation"
            customClass="normal-roll-button normal-roll-btn"
          />
        </div>
      </div>
    </section>
  );
};

export default cloneScripts;
