import React from "react";

const boxData = [
  {
    id: 0,
    title: "User Features",
    lists: [
      "Compatibility Across Multiple Languages",
      "P2P/Spot/Futures Trading Options",
      "Strong Trading System",
      "Trading Insights and Mirror Trading Features",
      "Interoperable Wallet for Cross-Chain Trading",
      "Record of Transactions and Order History",
    ],
  },
  {
    id: 1,
    title: "Administrator Features",
    lists: [
      "Monitor Transaction Logs",
      "Pair Exchange Control",
      "Endless Income Modules",
      "API Liquidity Management",
      "Dispute Handling",
      "Zealous & Multifunctional Panel",
    ],
  },
  {
    id: 2,
    title: "Exclusive Features",
    lists: [
      "Token Offering Options",
      "Finance Options: Loans, Trades, and Staking",
      "Versatile Payment Gateway",
      "Automated Cryptocurrency Trading System",
      "Cryptocurrency Price Ticker API",
      "User Interface API",
    ],
  },
];

const exchangeSoftware = () => {
  return (
    <section className="light-gray-bg">
      <div className="hero-wrapper item-center gap-2xl">
        <div className="item-center gap-sm">
          <h2 className="about-h2 c-text-center md-c-text-start">
            Key Features of our Crypto Exchange Software
          </h2>
          <p className="about-p c-text-center md-c-text-start">
            Our crypto exchange software is equipped with advanced trading tools
            designed to maximize transaction speed, security, and user
            efficiency. An admin dashboard enables platform management,
            real-time monitoring, and complete control over exchange operations
            from a single interface.
          </p>
        </div>
        <div className="crypto-exchange-software-boxes c-grid grid-three gap-xl">
          {boxData.map((data, index) => (
            <div
              key={index}
              className="crypto-exchange-software-box item-start  gap-md"
            >
              <p className="about-h5 font-black c-text-center">{data.title}</p>
              {data.lists.map((list, index) => (
                <div
                  className="crypto-exchange-software-list about-p flex-center "
                  key={index}
                >
                  <span></span>
                  {list}
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default exchangeSoftware;
