import React from "react";

const boxData = [
  "Option Trading",
  "Crypto Loan",
  "Stake & Earn",
  "Prediction Game",
  "Trading Completion",
  "Copy Trading",
  "Launchpad",
  "Trading Bot with AI",
  "Market Making Bot with Liquidity & Price Maintenance",
  "Referral Commission",
  "Affiliate Marketing Dashboard",
  "Business API",
  "Ticketing System",
  "ETF Trading",
  "ETF Development",
  "P2P",
  "Cross & Isolated Derivatives Trading",
];

const tradingIntegration = () => {
  return (
    <section className="hero-wrapper item-center gap-xl">
      <h2 className="about-h2 c-text-center md-c-text-start">
        Prebuilt Trading Modules for Seamless Integration
      </h2>
      <div className="c-grid grid-four crypto-integration-cards">
        {boxData.map((data, index) => (
          <div key={index} className="crypto-integration-card">
            <span className="about-p-two fw-600">{data}</span>
          </div>
        ))}
      </div>
    </section>
  );
};

export default tradingIntegration;
