import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import CryptoExchangeScreen from "@screens/crypto-exchange";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const CryptoDevelopment = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Cryptocurrency Exchange Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.cryptoExchangeDevelopmentImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Justtry Technologies is a leading cryptocurrency exchange development company offering secure and custom blockchain solutions.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },
      {
        "@type": "Product",
        name:
          validData?.title ||
          "Cryptocurrency Exchange Development Company - Justtry Technologies",
        description:
          "Leading cryptocurrency exchange development company Justtry Technologies offers white-label crypto exchange solutions at an affordable cost. Hire expert crypto developers today.",
        url: "https://justtrytech.com/cryptocurrency-exchange-development-company/",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
          logo: "https://justtrytech.com/static/706f5704167d4af95b1b87c4a1165942/f541b/crypto-exchange-development.png",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.5,
          reviewCount: 422,
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "What is cryptocurrency exchange development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Cryptocurrency exchange development involves building secure platforms that allow users to trade digital assets such as Bitcoin, Ethereum, and other cryptocurrencies.",
            },
          },
          {
            "@type": "Question",
            name: "Does Justtry Technologies provide custom crypto exchange solutions?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, Justtry Technologies offers fully customizable centralized, decentralized, and hybrid cryptocurrency exchange development solutions tailored to business needs.",
            },
          },
          {
            "@type": "Question",
            name: "Are the cryptocurrency exchanges secure?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, the exchanges are built with advanced security features including encryption, multi-factor authentication, and smart contract audits.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <CryptoExchangeScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default CryptoDevelopment;

export const queryData = graphql`
  query MyQuery {
    cryptoExchangeDevelopmentImg: file(
      relativePath: { eq: "crypto-exchange-development.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "cryptocurrency-exchange-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
