const techs = (props) => {
  const { db } = props;

  const [activeCategory, setActiveCategory] = useState("programming");

  const categories = Object.values(
    boxData.reduce((acc, item) => {
      if (!acc[item.category]) {
        acc[item.category] = {
          key: item.category,
          catName: item.catName,
        };
      }
      return acc;
    }, {})
  );

  const filteredData = boxData.filter(
    (data) => data.category === activeCategory
  );

  return (
    <section className="hero-wrapper item-center gap-2xl">
      <div className="item-center gap-sm">
        <h2 className="about-h2 font-black c-text-center md-c-text-start">
          Our Technology Stack for Cryptocurrency Exchange Development
        </h2>
        <p className="about-p font-black c-text-center md-c-text-start">
          As a premier Cryptocurrency Exchange Development Company, we provide
          top-notch customized solutions that incorporate a modern technology
          stack to meet your unique business needs.
        </p>
      </div>
      <div className="w-100 item-center c-gap">
        <div className="gap-md crypto-stacks-category-btns col_flex">
          {categories.map((cat) => (
            <div key={cat.id} className="home-stacks-category-accord">
              <button
                key={cat.key}
                className={`crypto-stacks-category-btn about-p fw-600 ${
                  activeCategory === cat.key
                    ? "crypto-stacks-category-btn-active"
                    : ""
                }`}
                onClick={() => setActiveCategory(cat.key)}
              >
                {cat.catName}
              </button>
              {activeCategory === cat.key && (
                <div className="accordion-modal-box ">
                  {filteredData.map((data) => (
                    <div
                      key={data.id}
                      className={`flex-center gap-sm crypto-stacks-card w-100`}
                    >
                      <div className="accordian-stact-image">
                        <img src={data.icon} alt={data.title} />
                      </div>
                      <p className="about-p-two fw-600 font-black text-nowrap">
                        {data.title}
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
        <div className="gap-md crypto-stacks-cards col_flex">
          {filteredData.map((data) => (
            <div
              key={data.id}
              className="flex-center gap-md crypto-stacks-card"
            >
              <img src={data.icon} alt={data.title} width={50} />
              <p className="about-p-two fw-600 font-black text-nowrap">
                {data.title}
              </p>
            </div>
          ))}
        </div>
      </div>
      <div className="buttons">
        <Link to={Justtrylinks.contactUs} className="roll-button roll-btn">
          <span>View Live Demo</span>
        </Link>
        <TalkToUsNew
          db={db}
          label="Free Consultation"
          customClass="normal-roll-button normal-roll-btn"
        />
      </div>
    </section>
  );
};

export default techs;
