import { StaticImage } from "gatsby-plugin-image";
import React from "react";
import biometric from "@styles/assets/images/Crypto/biometric.svg";
import ddos from "@styles/assets/images/Crypto/ddos.svg";
import digital_document from "@styles/assets/images/Crypto/digital-document.svg";
import digital_identity from "@styles/assets/images/Crypto/digital-identity.svg";
import https from "@styles/assets/images/Crypto/https.svg";
import mobile from "@styles/assets/images/Crypto/mobile.svg";
import prevention from "@styles/assets/images/Crypto/prevention.svg";
import sql_injection from "@styles/assets/images/Crypto/sql-injection.svg";

const boxData = [
  {
    id: 0,
    title: "Automated KYC and AML Verification with AI",
    icon: digital_identity,
  },
  {
    id: 1,
    title: "Identity Verification through Biometrics",
    icon: biometric,
  },
  {
    id: 2,
    title: "Two Factors Authentication",
    icon: mobile,
  },
  {
    id: 3,
    title: "Encrypted Data Storage",
    icon: digital_document,
  },
  {
    id: 4,
    title: "Prevention of High-Volume Transactions",
    icon: prevention,
  },
  {
    id: 5,
    title: "DDoS Protection",
    icon: ddos,
  },
  {
    id: 6,
    title: "SQL Injection Prevention",
    icon: sql_injection,
  },
  {
    id: 7,
    title: "HTTPs Authentication",
    icon: https,
  },
];
const secure = () => {
  return (
    <section className="hero-wrapper item-center gap-xl">
      <div className="item-center">
        <h2 className="about-h2 font-black c-text-center md-c-text-start">
          Secure your crypto business with our Cryptocurrency Exchange Software
          Solutions
        </h2>
        {/* <p className="about-p font-black c-text-center md-c-text-start">
          We implement enterprise-grade security protocols to safeguard user
          assets and exchange operations. Our cryptocurrency exchange software
          company integrates advanced protection mechanisms that enhance trust,
          ensure regulatory compliance, and support long-term business growth.
        </p> */}
      </div>
      <div className="flex-center md-flex-column gap-2xl ">
        <StaticImage
          src="../../../styles/assets/images/Crypto/crypto_laptop.png"
          alt="crypto exchange"
          fetchpriority="high"
          layout="constrained"
          width={1400}
          loading="eager"
          placeholder="none"
        />
        <div className="item-start gap-md w-100">
          {boxData.map((data, index) => (
            <div key={index} className="crypto-secure-card flex-center gap-sm">
              <img src={data.icon} alt={data.title} />
              <p className="about-p-two">{data.title}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default secure;
