import React from "react";
import assurance from "@styles/assets/images/Crypto/assurance.svg";
import fluent_people from "@styles/assets/images/Crypto/fluent_people.svg";
import idea from "@styles/assets/images/Crypto/idea.svg";
import ui_ux from "@styles/assets/images/Crypto/ui_ux.svg";
import call_return from "@styles/assets/images/Crypto/call_return.svg";

const boxData = [
  {
    id: 0,
    title: "In-House Team of Experts",
    icon: fluent_people,
  },
  {
    id: 1,
    title: "Bug-Free Solutions",
    icon: idea,
  },
  {
    id: 2,
    title: "Round-the-Clock Support",
    icon: call_return,
  },
  {
    id: 3,
    title: "Intuitive UI/UX",
    icon: ui_ux,
  },
  {
    id: 4,
    title: "Quality Assurance",
    icon: assurance,
  },
];
const whyChoose = () => {
  return (
    <section className="light-gray-bg">
      <div className="hero-wrapper item-center gap-2xl">
        <h2 className="about-h2 font-black c-text-center md-c-text-start">
          Why Choose Justtry Technologies as Your Cryptocurrency Exchange
          software Development company?
        </h2>
        <p className="about-p font-black c-text-center md-c-text-start">
          Justtry Tech is a Cryptocurrency Exchange software Development
          services based company that has engaged world customers to provide
          secure, scalable, and high-performance crypto exchange platforms. We
          have the option to develop a future-ready solution with advanced
          blockchain technology by our experienced in-house team, which was
          reliable, usable, and ensured long-term growth. We assist you in
          making a confident entry in the crypto market, from architecture to
          launch, and support.
        </p>
        <div className="crypto-why-choose-cards c-grid grid-three gap-sm row-gap-5">
          {boxData.slice(0, 3).map((data, index) => (
            <div key={index} className="crypto-why-choose">
              <img src={data.icon} alt={data.title} />
              <p className="about-p-two fw-600">{data.title}</p>
            </div>
          ))}

          <div className="last-row gap-md">
            {boxData.slice(3).map((data, index) => (
              <div key={index} className="crypto-why-choose">
                <img src={data.icon} alt={data.title} />
                <p className="about-p-two fw-600">{data.title}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default whyChoose;
