import React from "react";
import "./style.css";
import crypto_process from "@styles/assets/images/Crypto/crypto_process.png";

import Hero from "./hero";
import Overview from "./overview";
import Servicehiglightsection from "@components/common/service-higlight-section";
import Service from "./service";
import TradingIntegration from "./tradingIntegration";
import CloneScripts from "./cloneScripts";
import BlockChainNetwork from "./blockChainNetwork";
import ExchangeSoftware from "./exchangeSoftware";
import Approach from "./approach";
import Secure from "./secure";
import WhyChoose from "./whyChoose";
import Faq from "./faq";
import Techs from "./techs";
import ServiceStickySection from "@components/common/serviceStickySection";

const StickSectionData = {
  title: "Our Cryptocurrency Exchange Development Process",
  image: crypto_process,
  boxData: [
    {
      id: 1,
      desc: "Grasp concept, objectives, project prerequisites, acknowledge client priorities initially.",
    },
    {
      id: 2,
      desc: "Research, finalize resources, time, clear workflow, roadmap, quality output assured.",
    },
    {
      id: 3,
      desc: "Designing exchange starts with a skilled team for UI/UX, create intuitive, user-friendly dash boards, high-end flow.",
    },
    {
      id: 4,
      desc: "Crypto exchange development by skilled developers with advanced tech expertise is essential for success.",
    },
    {
      id: 5,
      desc: "We integrate key 3rd party service for smooth functionality, with liquidity providers & digital payment systems.",
    },
    {
      id: 6,
      desc: "Platform undergoes rigorous testing, smart contract audits, and beta tests before launch.",
    },
  ],
};
const CryptoExchange = (props) => {
  const { db } = props;
  return (
    <>
      <Hero db={db} />
      <Overview />
      <Servicehiglightsection
        content={
          "Join the Crypto Craze with Our State-of-the-Art Cryptocurrency Exchange Today!"
        }
      />
      <Service />
      <TradingIntegration />
      <CloneScripts db={db} />
      <BlockChainNetwork />
      <ExchangeSoftware />
      <Secure />
      <Approach />
      <Techs db={db} />
      <ServiceStickySection sectionData={StickSectionData} />
      <Servicehiglightsection
        content={"Take Your Business to the Next Level With Us!"}
      />
      <WhyChoose />
      <Faq />
    </>
  );
};

export default CryptoExchange;
